#include<bits/stdc++.h>
using namespace std;
void swap(char &a,char &b){
	char t=a;
	a=b;
	b=t;
}
int main() {
	int t;
	cin >> t;
	while (t--) {
		string a, b, c;
		cin >> a >> b >> c;
		if (a[1] == '>') swap(a[0], a[2]);
		if (b[1] == '>') swap(b[0], b[2]);
		if (c[1] == '>') swap(c[0], c[2]);
		if (a[0] == b[0]) cout << a[0] << c[0] << c[2] << "\n";
		else if (b[0] == c[0]) cout << b[0] << a[0] << a[2] << "\n";
		else if (a[0] == c[0]) cout << c[0] << b[0] << b[2] << "\n";
		else cout << "Impossible" << "\n";
	}
	return 0;
}
